import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart, PieChart, ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface SubjectBreakdown {
  subject: string;
  hours: number;
}

interface WeeklyComparison {
  day: string;
  hours: number;
}

interface StudyData {
  todayStudyHours: number;
  subjectBreakdown: SubjectBreakdown[];
  weeklyComparison: WeeklyComparison[];
}

export default function Widget() {
  const studyData = response.data as StudyData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h5" color="primary" sx={{ mb: 1 }}>
              Today's Study Hours
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFC107' }}>
              {studyData.todayStudyHours} hrs
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: studyData.weeklyComparison.map(w => w.hours),
                  color: '#FF5722',
                  label: 'Hours',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: studyData.weeklyComparison.map(w => w.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'hours' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsYAxis
                axisId="hours"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <PieChart
              height={150}
              series={[
                {
                  data: studyData.subjectBreakdown.map(subject => ({
                    value: subject.hours,
                    label: subject.subject,
                  })),
                  color: '#FFC107',
                },
              ]}
              sx={{
                '& .MuiPieElement-root': {
                  stroke: '#1E293B',
                  strokeWidth: 2,
                },
              }}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
